import{_ as n,C as s,o,c as l,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Switzerland Healthcare","description":"Healthcare and HRT access for transgender people in Switzerland","frontmatter":{"layout":"doc","title":"Switzerland Healthcare","description":"Healthcare and HRT access for transgender people in Switzerland"},"headers":[],"relativePath":"europe/switzerland/healthcare.md","filePath":"europe/switzerland/healthcare.md","lastUpdated":null}'),c={name:"europe/switzerland/healthcare.md"};function h(u,e,g,p,m,f){const t=s("Badge");return o(),l("div",null,[r(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[i("Informed Consent Available",-1)])]),_:1}),r(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[i("Major University Clinics",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-switzerland" tabindex="-1">Healthcare in Switzerland <a class="header-anchor" href="#healthcare-in-switzerland" aria-label="Permalink to &quot;Healthcare in Switzerland&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Switzerland has a unique healthcare system where <strong>major university hospitals</strong> offer informed-consent-based trans care, while other regions may be more restrictive. The Swiss healthcare system is decentralized, with cantons responsible for healthcare delivery.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><h3 id="informed-consent-at-major-clinics" tabindex="-1">Informed Consent at Major Clinics <a class="header-anchor" href="#informed-consent-at-major-clinics" aria-label="Permalink to &quot;Informed Consent at Major Clinics&quot;">​</a></h3><p>The following university hospitals operate an <strong>informed consent model</strong>:</p><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th></tr></thead><tbody><tr><td><strong>University Hospital Zurich (USZ)</strong></td><td>Zurich</td><td>Full spectrum: HRT, surgery, psych</td><td>DE, EN, FR</td></tr><tr><td><strong>CHUV Lausanne</strong></td><td>Lausanne</td><td>HRT, surgical referrals</td><td>FR, EN, DE</td></tr><tr><td><strong>Inselspital Bern</strong></td><td>Bern</td><td>HRT, assessments</td><td>DE, EN, FR</td></tr><tr><td><strong>University Hospital Basel (USB)</strong></td><td>Basel</td><td>HRT, comprehensive care</td><td>DE, EN</td></tr><tr><td><strong>Hôpitaux Universitaires de Genève (HUG)</strong></td><td>Geneva</td><td>HRT, counselling</td><td>FR, EN, DE</td></tr></tbody></table><h3 id="process-at-informed-consent-clinics" tabindex="-1">Process at Informed Consent Clinics <a class="header-anchor" href="#process-at-informed-consent-clinics" aria-label="Permalink to &quot;Process at Informed Consent Clinics&quot;">​</a></h3><ol><li><strong>Initial Contact</strong> — Self-referral or GP referral to the trans care unit</li><li><strong>Consultation</strong> — Discussion of treatment goals, medical history</li><li><strong>Informed Consent</strong> — Sign consent form after understanding risks and benefits</li><li><strong>Blood Tests</strong> — Baseline hormone levels and health markers</li><li><strong>Prescription</strong> — Hormones prescribed at the first or second appointment</li><li><strong>Follow-up</strong> — Regular monitoring every 3-6 months</li></ol><h3 id="regional-gatekeeping" tabindex="-1">Regional Gatekeeping <a class="header-anchor" href="#regional-gatekeeping" aria-label="Permalink to &quot;Regional Gatekeeping&quot;">​</a></h3><ul><li>In smaller cantons and rural areas, trans care may require: <ul><li>Psychiatric diagnosis</li><li>Referral to endocrinology</li><li>Longer wait times</li></ul></li><li>Private psychiatrists and endocrinologists in smaller cities may not have trans care experience</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>City</th><th>Model</th><th>Wait Times</th></tr></thead><tbody><tr><td>USZ - Transgender Health Unit</td><td>Zurich</td><td>Informed consent</td><td>2-4 months</td></tr><tr><td>CHUV - Unité de Médecine de Genre</td><td>Lausanne</td><td>Informed consent</td><td>2-4 months</td></tr><tr><td>Inselspital - Trans Care</td><td>Bern</td><td>Informed consent</td><td>3-5 months</td></tr><tr><td>USB - Gender Unit</td><td>Basel</td><td>Informed consent</td><td>3-5 months</td></tr><tr><td>HUG - Unité de Genre</td><td>Geneva</td><td>Informed consent</td><td>3-5 months</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>Switzerland is not in the EU/EEA</strong> — EU prescription cross-border rules do not fully apply</li><li><strong>EU prescriptions</strong>: May be accepted but require Swiss doctor verification</li><li><strong>Non-EU prescriptions</strong>: Must be verified by a Swiss doctor</li><li><strong>Importing medication</strong>: Keep in original packaging with prescription label</li><li>Carry a doctor&#39;s letter (English, German, or French) explaining the medication</li><li>Swiss health insurance (basic coverage) covers trans-related care including HRT</li></ul><h2 id="insurance-coverage" tabindex="-1">Insurance Coverage <a class="header-anchor" href="#insurance-coverage" aria-label="Permalink to &quot;Insurance Coverage&quot;">​</a></h2><p>Switzerland has mandatory <strong>health insurance (Krankenversicherung / assurance maladie)</strong>:</p><ul><li>Basic insurance covers gender-affirming treatments</li><li>HRT medications are covered with a prescription</li><li>Coverage for surgery requires a medical report and insurance approval</li><li>Deductible (franchise) typically 300-2,500 CHF/year</li><li>Co-payment (Selbstbehalt) is 10% up to 700 CHF/year</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries available at major university hospitals</li><li>Referral from a recognized clinic required</li><li>Insurance covers surgeries after medical necessity is established</li><li>Wait times: 6-12 months for consultation, 6-18 months for surgery</li><li>FFS (facial feminization surgery) may not be fully covered</li></ul><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li>Psychiatrists at university clinics</li><li><strong>TGNS (Transgender Network Switzerland)</strong> — Peer support groups</li><li><strong>Pink Cross</strong> — LGBTQ+ counselling</li><li>Private therapists with trans experience (80-150 CHF/session)</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Typical Cost</th><th>Insurance Coverage</th></tr></thead><tbody><tr><td>GP visit</td><td>80-150 CHF</td><td>Covered (after deductible)</td></tr><tr><td>Endocrinology consult</td><td>150-300 CHF</td><td>Covered</td></tr><tr><td>HRT (monthly)</td><td>30-80 CHF</td><td>Covered</td></tr><tr><td>Blood tests</td><td>50-200 CHF</td><td>Covered</td></tr><tr><td>Private therapy</td><td>80-150 CHF</td><td>Partially covered</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.tgns.ch/" target="_blank" rel="noreferrer">TGNS - Transgender Network Switzerland</a></li><li><a href="https://www.usz.ch/" target="_blank" rel="noreferrer">USZ - Transgender Health Unit</a></li><li><a href="https://www.chuv.ch/" target="_blank" rel="noreferrer">CHUV Unité de Médecine de Genre</a></li><li><a href="https://www.insel.ch/" target="_blank" rel="noreferrer">Inselspital Bern</a></li><li><a href="https://www.comparis.ch/" target="_blank" rel="noreferrer">Swiss Health Insurance (Comparis)</a></li></ul>',26))])}const v=n(c,[["render",h]]);export{y as __pageData,v as default};
